"use client";

import React, { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import styles from './login.module.css';
import { jwtDecode } from "jwt-decode"; 

export default function LoginPage() {
  const router = useRouter();
  const hasAlerted = useRef(false);
  const [isLoading, setIsLoading] = useState(true);
  
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });

  // 1. 페이지 진입 시 로그인 상태 체크
  useEffect(() => {
    const token = localStorage.getItem("token");

    if (token) {
      if (!hasAlerted.current) {
        hasAlerted.current = true;
        alert("이미 로그인된 상태입니다.");
        router.replace('/main');
      }
    } else {
      setIsLoading(false);
    }
  }, [router]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      const response = await fetch('http://localhost:8080/api/member/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        const data = await response.json();
        const token = data.accessToken || data.token;
        
        // 🚀 토큰 저장
        localStorage.setItem('token', token);
        
        // 🚀 토큰에서 userId 추출 및 저장
        try {
          const decoded: any = jwtDecode(token);
          if (decoded.userId) {
            localStorage.setItem('userId', String(decoded.userId));
            console.log("userId 저장 완료:", decoded.userId);
          }
        } catch (decodeError) {
          console.error("토큰 디코딩 실패:", decodeError);
        }

        alert("로그인 되었습니다!");
        window.location.href = '/main'; 
      } else {
        alert("이메일 또는 비밀번호를 확인해주세요.");
      }
    } catch (error) {
      console.error("Login Error:", error);
      alert("서버 오류가 발생했습니다. 잠시 후 다시 시도해주세요.");
    }
  };

  if (isLoading) {
    return null; // 로딩 중에는 아무것도 렌더링하지 않음
  }

  return (
    <div className={styles.container}>
      <h2 className={styles.title}>로그인</h2>
      <form onSubmit={handleLogin} className={styles.form}>
        
        <div className={styles.inputGroup}>
          <label className={styles.label}>이메일</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            className={styles.input}
            placeholder="이메일 입력"
            required
          />
        </div>

        <div className={styles.inputGroup}>
          <label className={styles.label}>비밀번호</label>
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handleChange}
            className={styles.input}
            placeholder="비밀번호 입력"
            required
          />
        </div>

        <button type="submit" className={styles.button}>로그인</button>

        <div className={styles.footer}>
          <Link href="/authJoin" className={styles.link}>회원가입 하기</Link>
        </div>
      </form>
    </div>
  );
}